// src/utils/convertToPandocFormat.ts
function convertToPandocFormat(content) {
  let result = content.replace(/\[\[(.*?)\|.*?\]\]/g, "[[$1]]");
  result = result.replace(/\[\[@(.*?)\]\]/g, "[@$1]");
  result = result.replace(/\](\s*?)\[@/g, ";@");
  result = result.replace(/(\.)\s*?(\[@.*?\])/g, " $2$1 ");
  return result;
}

